VALUES
  ('cpa-moex-01526', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列各項有關產品別獲利分析之敘述，何者錯誤？', '["產品別獲利分析應包含與個別客戶有關之銷售與行銷成本分析，故產品別獲利分析即為客戶別獲 利分析", "作業基礎成本制有助於企業計算其產品成本", "分析評估企業各項產品產銷作業活動之附加價值乃產品別獲利分析之主要目的之一", "產品別獲利分析有助於企業產品產銷組合決策之作成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01527', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '會計部門正在計算客戶別之銷售報酬率（return on sales）。相關資料列示如下： 客戶甲    客戶乙    客戶丙 銷貨    $500,000    $1,200,000    $800,000 邊際貢獻    160,000    360,000    280,000 營業成本    (90,000)    (410,000) (180,000) 若營業成本為固定成本，為使客戶乙之銷貨報酬率不為負，則對其銷貨額應增加多少？', '["$166,667", "$585,714", "$614,286", "$1,366,667"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01528', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '某公司由於手動照相機事業部長久虧損，因而打算關閉這個事業部。這個事業部上一季的相關資訊 如下： 銷貨（1,000台）    $1,000,000 製造成本 直接材料    500,000 直接人工（每小時$50）    200,000 製造費用    400,000 營業損失    ($100,000) 製造費用成本其中70%屬於變動製造費用，其餘30%為該事業部所屬的特殊設備的折舊費用，該設 備無法出售給他人。如果這個事業部被關閉，營業利益將有何影響？', '["營業利益增加$100,000", "營業利益減少$20,000", "營業利益增加$180,000", "營業利益減少$120,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01529', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '太陽公司是電視製造商，目前公司一舊款產品的邊際貢獻總額為4,000萬元，公司管理當局擬開發新 款的電視來取代此舊款電視，據公司高層估計成功的機率為 60%，成功後新款電視的總邊際貢獻為 10,000萬元，若失敗，則總邊際貢獻只有800萬元。試問完美資訊（perfect information）的價值為多 少？', '["1,280萬元", "6,000萬元", "6,320萬元", "7,600萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01530', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '和平公司採用現購政策，一年對A產品的需求量為60,000件。若每月初採購5,000件，每件售價 $100；若年初一次採購60,000件，則每件價格為$95。若和平公司的年投資報酬率為8%，則二種採 購方案的資金機會成本差異數為：', '["$208,000", "$228,000", "$416,000", "$456,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01531', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '大華公司購置設備之成本為$800,000，耐用年限8年，無殘值，採直線法折舊。未提列折舊費用前， 使用新設備預計每年會減少費用$50,000。若原始投資之會計報酬率（accrual accounting rate-of-return） 為20%，則該設備每年為公司增加的營業收入為多少？', '["$110,000", "$160,000", "$210,000", "$310,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01532', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '高立公司製造兩型的桌子--標準型與舒適型，下列是各型的相關作業與成本資訊： 產品    整備數    零件數   機器運轉小時數   直接人工小時數 標準型    11    4    8    375 舒適型    14    6    12    225 製造費用    $20,000    $30,000   $10,000 假設傳統成本法分攤製造費用$60,000，是採用直接人工小時，請問在傳統成本法下標準型應分攤多 少成本？', '["$22,500", "$24,800", "$35,200", "$37,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01533', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關「全面品質管制」觀念的說明，下列敘述正確者有幾項？', '["產品品質管制應於設計、開發、生產、銷售及售後服務之整體價值鏈中併同考量", "供應商須準時交貨，其原物料品質必須良好，且交易條件及價格合理", "產品品質是生產線員工的責任，與設計或研發部門無關", "必須編製品質成本報告，以進行品質控管績效評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01534', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '實施平衡計分卡時，第一步驟應為：', '["選擇關鍵績效指標", "設定長期之財務目標", "確立組織之願景及策略", "建立所需之資料庫與資訊系統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01535', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '月 31 日為股利分配日，共分配現金股利 3,000,000 元。假設甲公司無須提列法 定盈餘公積，且公司章程中未明定盈餘分配比率。請問（計算請詳列計算式，金額 四捨五入至元，百分比四捨五入至小數點後第二位）： 甲公司99年底股東可扣抵稅額帳戶餘額應為多少？（4分） 甲公司 100 年度申報繳納 98 年度未分配盈餘應加徵之營利事業所得稅稅額為多 少？（4分） 甲公司100年分配現金股利時，依公式計算之稅額扣抵比率為多少？稅額扣抵比 率上限為多少？應分配與股東之可扣抵稅額應為多少？（6分）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01536', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '現行所得稅法有關綜合所得稅申報房屋租金支出列舉扣除之規定，下列敘述何者錯誤？', '["已申報有購屋借款利息者，不得扣除", "在中華民國境內租屋，供自住且非供營業或執行業務使用者，始可申報", "每一申報戶每年扣除數額以12萬元為限", "納稅義務人之同胞兄弟姊妹在中華民國境內租屋者，其租金支出亦得申報扣除"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01537', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得稅法規定，個人參加多層次傳銷事業而銷售商品或提供勞務予消費者，全年進貨累積金額超 過新臺幣7萬元者，其全部銷售額所賺取之零售利潤，應申報為何類所得？', '["營利所得", "財產交易所得", "執行業務所得", "其他所得"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01538', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得稅相關法規規定，下列何種所得之扣繳率為20%？', '["受益人不特定之信託所得", "與銀行從事結構型商品之交易所得", "依金融資產證券化條例規定發行之受益證券之利息所得", "期貨交易所得"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01539', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得稅法規定，自94年度起，營利事業計算未分配盈餘加徵10%營利事業所得稅時，「未分配盈 餘」係指依商業會計法規定處理之稅後純益，減除特定項目後之餘額，該特定項目包括下列何者？', '["依規定應以費用列支之員工紅利及董監酬勞", "由以往年度盈餘分配之股利淨額或盈餘淨額", "彌補次一年度未經會計師查核簽證之虧損", "依其他法律規定，由主管機關命令提列之特別盈餘公積"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01540', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得稅法相關規定，下列有關營利事業費用限額之規定，何者錯誤？', '["營利事業為員工投保之團體壽險，由營利事業負擔保險費，每人每月在2,000元以內部分，免視為被保 險員工之薪資所得", "營利事業實際供給膳食或按月定額發給員工伙食代金，每人每月伙食費包括加班誤餐費，最高以 1,800 元 為限，免視為員工之薪資所得", "在臺以新臺幣支付國外佣金者，應在不超過出口貨物價款3%範圍內取具國外代理商或代銷商名義出具 之收據予以認定", "外銷損失金額每筆在新臺幣30萬元以下者，得免附國外公證或檢驗機構出具之證明文件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01541', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得基本稅額條例施行細則規定，營利事業短漏報基本所得額，致短漏稅額者，若稽徵機關依所 得基本稅額條例核定該營利事業之一般所得稅額高於基本稅額時，應依下列何項規定加以處罰？', '["依所得稅法規定處適當倍數之罰鍰", "依所得基本稅額條例規定處所漏稅額1倍以下之罰鍰", "依所得基本稅額條例規定處所漏稅額2倍以下之罰鍰", "依所得基本稅額條例規定處所漏稅額3倍以下之罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01542', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '美商A公司在中華民國境內提供技術服務，依所得稅法第25條規定向財政部申請核准，按其在我國境內 營業收入之15%為我國境內之營利事業所得額，其相關申請及適用規定下列何者正確？', '["A公司須在我國境內設有分支機構", "A公司須在我國境內設有營業代理人", "A公司不可適用所得稅法中關於虧損扣除之規定", "A公司在我國境內從事技術服務之成本費用分攤計算須完整清楚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01543', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行所得基本稅額條例規定，營利事業基本所得稅額之稅率為多少？', '["8%～12%", "10%～12%", "12%～15%", "15%～20%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01544', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某使用統一發票之商號某日未滿新臺幣50元之交易計50筆，該商號開立發票之方式，下列何者不符合 現行加值型及非加值型營業稅法規定？', '["每日彙開所有未滿新臺幣50元之交易", "逐筆開立統一發票", "每月彙開所有未滿新臺幣50元之交易", "買受人要求即應開立統一發票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01545', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行加值型及非加值型營業稅法規定，進口下列何種貨物，不得免徵營業稅？', '["市政府進口緊急救難器材", "肥料", "私立大學進口教學設備", "新鮮水果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01546', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行加值型及非加值型營業稅法規定，外國國際運輸業於我國境內無固定營業場所但有營業代理人者， 其自國外載運貨物入境並於境內收取運費者，下列敘述何者正確？', '["代理人應依規定開立發票，自行報繳營業稅", "代理人無需開立發票，但應自行報繳營業稅", "代理人應依規定開立發票，但可免稅", "其非營業稅課稅範圍，代理人無需開立發票，亦免報繳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01547', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行加值型及非加值型營業稅法規定，營業人未依規定期限申報銷售額或統一發票明細表者，稅捐稽徵 機關依法可處下列何種處罰？', '["滯報金及滯納金", "滯報金及怠報金", "怠報金及滯納金", "滯納金及罰鍰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01548', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '賈富貴出售土地一筆，售價為150萬元，買賣雙方以公告現值100萬元申報土地增值稅，賈富貴取得土 地時之申報移轉現值為20萬元，物價指數較取得時上漲20%，取得後未支付任何改良費用，請問其應課 稅之土地增值額為若干？', '["76萬元", "80萬元", "126萬元", "130萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01549', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行土地稅法規定，下列關於重購土地退還土地增值稅規定之敘述，何者錯誤？', '["必須是重購土地之地價總額超過原出售土地之地價總額減去繳納土地增值稅額之餘額，才能退稅", "賣地後2年內以配偶之名義購地，不得退稅", "賣地後2年內將原地購回，不得退稅", "原地出售之自用住宅用地若未按優惠稅率核課土地增值稅者，即不得退稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01550', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '私人捐贈供興辦社會福利事業使用之土地，免徵土地增值稅。但受贈土地之財團法人，未按捐贈目的使 用土地者，除追補應納稅額外，並處多少罰鍰？', '["應納土地增值稅額之1倍", "應納土地增值稅額之2倍", "應納土地增值稅額之3倍", "應納土地增值稅額之5倍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
